def get_icon_svg(name: str, color: str = "currentColor", size: int = 24) -> str:
    """Return an SVG string for the given icon name, substituting color."""
    raw = ICONS.get(name, "")
    if not raw:
        return ""
    return raw.replace("currentColor", color).replace(
        'viewBox="0 0 24 24"',
        f'viewBox="0 0 24 24" width="{size}" height="{size}"'
    )
